### Conversation Thread Display
```rust
pub struct ConversationThread<'a> {
    tweets: &'a [Tweet],
    theme: &'a Theme,
    highlight_terms: Vec<String>,
}

impl<'a> ConversationThread<'a> {
    pub fn new(tweets: &'a [Tweet], theme: &'a Theme) -> Self {
        Self {
            tweets,
            theme,
            highlight_terms: vec![],
        }
    }

    pub fn highlight_terms(mut self, terms: Vec<String>) -> Self {
        self.highlight_terms = terms;
        self
    }

    pub fn render(&self, output: &Output) {
        if !output.is_styled() {
            for tweet in self.tweets {
                TweetCard::new(tweet, self.theme).render_plain(output);
            }
            return;
        }

        let tree_chars = ["│", "├", "└", "─"];

        for (i, tweet) in self.tweets.iter().enumerate() {
            let is_last = i == self.tweets.len() - 1;

            // Tree prefix
            if i > 0 {
                let prefix = if is_last {
                    format!("[{}]{}{} [/]", self.theme.muted, tree_chars[2], tree_chars[3])
                } else {
                    format!("[{}]{}{} [/]", self.theme.muted, tree_chars[1], tree_chars[3])
                };
                output.print(&prefix);
            }

            TweetCard::new(tweet, self.theme)
                .highlight_terms(self.highlight_terms.clone())
                .render(output, output.width());
        }
    }
}
