```rust
// tests/daemon_config_e2e.rs
use std::io::Write;
use tempfile::NamedTempFile;

#[test]
fn test_config_load_valid_toml() {
    let config_content = r#"
[daemon]
nice_level = 15
memory_limit_mb = 1024
max_threads = 2
idle_timeout_secs = 600
io_priority = "best_effort"
socket_path = "/tmp/test-xf.sock"
"#;

    let mut file = NamedTempFile::new().unwrap();
    file.write_all(config_content.as_bytes()).unwrap();
    let path = file.path().to_path_buf();

    let config = DaemonConfig::load(Some(&path)).unwrap();

    assert_eq!(config.resources.nice_level, 15);
    assert_eq!(config.resources.memory_limit_mb, 1024);
    assert_eq!(config.resources.max_threads, 2);
    assert_eq!(config.idle_timeout, Duration::from_secs(600));

    tracing::info!(?config, "Config loaded from TOML");
}

#[test]
fn test_config_load_invalid_toml() {
    let config_content = "this is not valid toml {{{";

    let mut file = NamedTempFile::new().unwrap();
    file.write_all(config_content.as_bytes()).unwrap();
    let path = file.path().to_path_buf();

    let result = DaemonConfig::load(Some(&path));
    assert!(result.is_err());
    tracing::info!(error = %result.unwrap_err(), "Invalid TOML correctly rejected");
}

#[test]
fn test_config_load_missing_file_uses_defaults() {
    let path = PathBuf::from("/nonexistent/path/config.toml");
    let config = DaemonConfig::load(Some(&path)).unwrap();

    // Should use defaults
    assert_eq!(config.resources.nice_level, 10);
    assert_eq!(config.resources.memory_limit_mb, 2048);
    tracing::info!("Missing file correctly uses defaults");
}

#[test]
fn test_config_env_override() {
    // Set environment variables
    std::env::set_var("XF_DAEMON_NICE", "19");
    std::env::set_var("XF_DAEMON_MEMORY_MB", "512");
    std::env::set_var("XF_DAEMON_THREADS", "1");

    let config = DaemonConfig::load(None).unwrap();

    assert_eq!(config.resources.nice_level, 19);
    assert_eq!(config.resources.memory_limit_mb, 512);
    assert_eq!(config.resources.max_threads, 1);

    // Cleanup
    std::env::remove_var("XF_DAEMON_NICE");
    std::env::remove_var("XF_DAEMON_MEMORY_MB");
    std::env::remove_var("XF_DAEMON_THREADS");

    tracing::info!("Environment overrides applied");
}

#[test]
fn test_config_env_overrides_file() {
    // Create config file with one value
    let config_content = r#"
[daemon]
nice_level = 5
memory_limit_mb = 2000
"#;

    let mut file = NamedTempFile::new().unwrap();
    file.write_all(config_content.as_bytes()).unwrap();
    let path = file.path().to_path_buf();

    // Set env to override one value
    std::env::set_var("XF_DAEMON_NICE", "10");

    let config = DaemonConfig::load(Some(&path)).unwrap();

    // nice_level should be from env (10), memory from file (2000)
    assert_eq!(config.resources.nice_level, 10, "Env should override file");
    assert_eq!(config.resources.memory_limit_mb, 2000, "File value preserved");

    std::env::remove_var("XF_DAEMON_NICE");
    tracing::info!("Env > file precedence verified");
}

#[tokio::test]
async fn test_daemon_uses_config_file() {
    let config_content = r#"
[daemon]
idle_timeout_secs = 5
"#;

    let mut file = NamedTempFile::new().unwrap();
    file.write_all(config_content.as_bytes()).unwrap();
    let config_path = file.path().to_path_buf();

    // Start daemon with config file
    let daemon = DaemonProcess::spawn_with_config_file(&config_path).await.unwrap();

    // Wait slightly more than idle timeout
    tokio::time::sleep(Duration::from_secs(6)).await;

    // Daemon should have exited due to idle timeout
    let exit_status = daemon.child.try_wait().unwrap();
    assert!(exit_status.is_some(), "Daemon should exit after idle timeout from config");

    tracing::info!("Config file idle_timeout honored");
}
