    /// Total document count
    pub doc_count: usize,
    /// Fast embedding dimensions
    pub fast_dims: usize,
    /// Quality embedding dimensions
    pub quality_dims: usize,
}

pub enum IndexStatus {
    /// Only fast embeddings available (quality indexing not started)
    FastOnly,
    /// Quality embeddings being computed in background
    QualityPartial { 
        progress: f32,           // 0.0 to 1.0
        docs_complete: usize,
        started_at: DateTime<Utc>,
    },
    /// Both tiers fully indexed
    Complete { completed_at: DateTime<Utc> },
