### 1.2 Indexing Strategy
```rust
/// Indexing CLI: xf index --two-tier [--quality-background]
pub async fn build_two_tier_index(
    docs: &[Document],
    config: &TwoTierConfig,
    output: &Output,
) -> Result<TwoTierIndex> {
    let total = docs.len();

    // Phase 1: Fast embeddings (mandatory, blocking)
    // Uses in-process Model2Vec - very fast (~1ms/doc)
    output.print_progress("Building fast embeddings (Model2Vec)...");
    let fast = Model2VecEmbedder::new(&config.fast_model)?;
    let fast_embeddings = fast.embed_batch_parallel(docs)?;
    output.print_success(&format!("Fast embeddings complete: {} docs", total));

    // Phase 2: Quality embeddings (optional, can be background)
    if config.quality_background {
        // Start background job, return immediately with FastOnly status
        spawn_background_quality_indexer(docs.clone(), config.clone());

        return Ok(TwoTierIndex {
            fast_embeddings,
            quality_embeddings: MmapVec::empty(),
            doc_ids: docs.iter().map(|d| d.id).collect(),
            metadata: TwoTierMetadata {
                status: IndexStatus::FastOnly,
                ..
            },
        });
    }

    // Foreground quality indexing
    output.print_progress("Building quality embeddings (MiniLM via daemon)...");
    let mut client = DaemonClient::new();

    // Batch for efficiency (100 docs at a time)
    let mut quality_embeddings = Vec::with_capacity(total);
    for (i, batch) in docs.chunks(100).enumerate() {
        let texts: Vec<&str> = batch.iter().map(|d| d.text.as_str()).collect();
        let embs = client.embed(&texts, Some(&config.quality_model), None).await?;
        quality_embeddings.extend(embs);

        output.update_progress((i * 100) as u64, total as u64);
    }

    Ok(TwoTierIndex {
        fast_embeddings,
        quality_embeddings: MmapVec::from_vec(quality_embeddings),
        doc_ids: docs.iter().map(|d| d.id).collect(),
        metadata: TwoTierMetadata {
            status: IndexStatus::Complete { completed_at: Utc::now() },
            ..
        },
    })
}
```

### 1.3 Background Quality Indexer
```rust
/// Background job that computes quality embeddings incrementally
pub struct BackgroundQualityIndexer {
    index_path: PathBuf,
    docs: Vec<Document>,
    config: TwoTierConfig,
    progress_file: PathBuf,  // ~/.xf/<archive>/.quality_progress
}

impl BackgroundQualityIndexer {
    pub async fn run(&self) -> Result<()> {
        let mut progress = self.load_progress()?;
        let mut client = DaemonClient::new();

        let remaining = &self.docs[progress.docs_complete..];

        for (i, batch) in remaining.chunks(100).enumerate() {
            let texts: Vec<&str> = batch.iter().map(|d| d.text.as_str()).collect();
            let embs = client.embed(&texts, Some(&self.config.quality_model), None).await?;

            // Append to quality embeddings file
            self.append_embeddings(&embs)?;

            // Update progress
            progress.docs_complete += batch.len();
            progress.progress = progress.docs_complete as f32 / self.docs.len() as f32;
            self.save_progress(&progress)?;

            // Rate limit to be nice
            tokio::time::sleep(Duration::from_millis(10)).await;
        }

        // Mark complete
        self.finalize()?;
        Ok(())
    }
}
```

