### 1.5 Index Invalidation
```rust
/// Called when documents are added/modified/deleted
pub fn invalidate_index(index: &mut TwoTierIndex, changed_doc_ids: &[u64]) {
    // Mark affected embeddings as stale
    for doc_id in changed_doc_ids {
        if let Some(idx) = index.doc_ids.iter().position(|&id| id == *doc_id) {
            index.metadata.stale_docs.insert(idx);
        }
    }

    // If too many stale (>10%), recommend full reindex
    let stale_pct = index.metadata.stale_docs.len() as f32 / index.doc_ids.len() as f32;
    if stale_pct > 0.10 {
        tracing::warn!(stale_pct = stale_pct, "Consider full reindex: xf index --rebuild");
    }
}
