### 2.2 Score Normalization (CRITICAL)
```rust
/// Normalize scores from different embedding spaces for blending
pub fn normalize_scores(
    fast_scores: &[f32],    // 256-dim cosine similarities
    quality_scores: &[f32], // 384-dim cosine similarities
) -> (Vec<f32>, Vec<f32>) {
    // Min-max normalization to [0, 1] range
    fn minmax(scores: &[f32]) -> Vec<f32> {
        if scores.is_empty() { return vec![]; }
        let min = scores.iter().cloned().fold(f32::INFINITY, f32::min);
        let max = scores.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
        let range = max - min;
        if range < 1e-6 {
            return vec![0.5; scores.len()]; // All same score
        }
        scores.iter().map(|s| (s - min) / range).collect()
    }

    (minmax(fast_scores), minmax(quality_scores))
}

/// Blend fast and quality scores
pub fn blend_scores(
    fast: &[f32],
    quality: &[f32],
    blend_factor: f32,  // 0.0 = all fast, 1.0 = all quality
) -> Vec<f32> {
    fast.iter()
        .zip(quality.iter())
        .map(|(f, q)| f * (1.0 - blend_factor) + q * blend_factor)
        .collect()
}
```

