## 3. Terminal Animation (DETAILED)

### 3.1 Cursor Control Strategy
```rust
use crossterm::{cursor, terminal, ExecutableCommand};

pub struct TwoTierRenderer {
    /// Number of lines currently displayed
    lines_displayed: usize,
    /// Whether we are in alternate screen buffer
    alternate_screen: bool,
}

impl TwoTierRenderer {
    /// Render initial results, save cursor position
    pub fn render_initial(&mut self, results: &[SearchResult], stdout: &mut Stdout) -> io::Result<()> {
        // Save cursor position
        stdout.execute(cursor::SavePosition)?;

        // Render results
        for (i, result) in results.iter().enumerate() {
            self.render_result(stdout, i, result, None)?;
        }

        self.lines_displayed = results.len();
        Ok(())
    }

    /// Re-render with rank changes, animating movements
    pub fn render_refined(
        &mut self, 
        results: &[SearchResult], 
        changes: &RankChanges,
        stdout: &mut Stdout,
    ) -> io::Result<()> {
        // Move cursor back to start of results
        stdout.execute(cursor::RestorePosition)?;

        // Re-render each result with movement indicators
        for (i, result) in results.iter().enumerate() {
            let movement = self.get_movement(result.doc_id, changes);
            self.render_result(stdout, i, result, movement)?;
        }

        // Clear any extra lines if fewer results
        self.clear_extra_lines(stdout, results.len())?;

        Ok(())
    }

    fn render_result(
        &self,
        stdout: &mut Stdout,
        rank: usize,
        result: &SearchResult,
        movement: Option<Movement>,
    ) -> io::Result<()> {
        // Clear current line
        stdout.execute(terminal::Clear(terminal::ClearType::CurrentLine))?;

        // Movement indicator
        let indicator = match movement {
            Some(Movement::Up(n)) => format!("↑{}", n).green(),
            Some(Movement::Down(n)) => format!("↓{}", n).red(),
            Some(Movement::New) => "★".yellow(),
            None => " ".normal(),
        };

        // Render: [rank] [indicator] [content preview]
        writeln!(stdout, "{:2}. {} {}", rank + 1, indicator, result.preview(60))?;

        Ok(())
    }

    fn get_movement(&self, doc_id: u64, changes: &RankChanges) -> Option<Movement> {
        for &(id, old, new) in &changes.promoted {
            if id == doc_id { return Some(Movement::Up(old - new)); }
        }
        for &(id, old, new) in &changes.demoted {
            if id == doc_id { return Some(Movement::Down(new - old)); }
        }
        None
    }
}

enum Movement {
    Up(usize),    // Moved up N positions
    Down(usize),  // Moved down N positions
    New,          // New in top results
}
```

### 3.2 Flicker Prevention
```rust
impl TwoTierRenderer {
    /// Use double buffering to prevent flicker
    pub fn render_with_buffer(&mut self, results: &[SearchResult], stdout: &mut Stdout) -> io::Result<()> {
        // Build complete output in memory first
        let mut buffer = String::new();

        for (i, result) in results.iter().enumerate() {
            buffer.push_str(&format!("{:2}. {}\n", i + 1, result.preview(60)));
        }

        // Write all at once
        stdout.execute(cursor::RestorePosition)?;
        write!(stdout, "{}", buffer)?;
        stdout.flush()?;

        Ok(())
    }

    /// Only animate if changes are significant
    pub fn should_animate(changes: &RankChanges, threshold: f32) -> bool {
        let total = changes.promoted.len() + changes.demoted.len() + changes.stable;
        if total == 0 { return false; }

        let change_ratio = (changes.promoted.len() + changes.demoted.len()) as f32 / total as f32;
        change_ratio >= threshold
    }
}
```

