        // With 50% blend, all should be 0.5 (average)
        assert!((blended[0] - 0.5).abs() < 0.001);
        assert!((blended[1] - 0.5).abs() < 0.001);
        assert!((blended[2] - 0.5).abs() < 0.001);
    }

    // === Kendall Tau Tests ===

    #[test]
    fn test_kendall_tau_identical() {
        let a = vec![1, 2, 3, 4, 5];
        let tau = kendall_tau(&a, &a);
        assert!((tau - 1.0).abs() < 0.001);
    }

    #[test]
    fn test_kendall_tau_reversed() {
        let a = vec![1, 2, 3, 4, 5];
        let b = vec![5, 4, 3, 2, 1];
        let tau = kendall_tau(&a, &b);
        assert!((tau - (-1.0)).abs() < 0.001);
    }

    // === Config Tests ===

    #[test]
    fn test_config_defaults() {
        let config = TwoTierConfig::default();
        assert_eq!(config.blend_factor, 0.7);
        assert_eq!(config.skip_refinement_threshold, 0.95);
        assert_eq!(config.refinement_timeout_ms, 500);
        assert!(config.fallback_on_daemon_error);
    }

    #[test]
    fn test_config_from_toml() {
        let toml = r#"
            blend_factor = 0.5
            skip_refinement_threshold = 0.9
            refinement_timeout_ms = 300
        "#;
        let config: TwoTierConfig = toml::from_str(toml).unwrap();
        assert_eq!(config.blend_factor, 0.5);
    }

    // === Index Status Tests ===

    #[test]
    fn test_index_status_fast_only() {
        let index = TwoTierIndex::new_fast_only(embeddings, doc_ids);
        assert!(matches!(index.metadata.status, IndexStatus::FastOnly));
    }

    #[test]
    fn test_index_status_partial() {
        let mut index = TwoTierIndex::new_fast_only(embeddings, doc_ids);
        index.update_quality_progress(50, 100);

        match index.metadata.status {
            IndexStatus::QualityPartial { progress, docs_complete, .. } => {
                assert!((progress - 0.5).abs() < 0.01);
                assert_eq!(docs_complete, 50);
            }
            _ => panic!("Expected QualityPartial"),
        }
    }

    // === Cancellation Tests ===

    #[tokio::test]
    async fn test_cancellation_before_refinement() {
        let cancel = CancellationToken::new();
        cancel.cancel();

        let searcher = TwoTierSearcher::new_with_cancel(fast, quality, index, config, cancel);
        let phases: Vec<_> = searcher.search("test", 10).collect().await;

        assert_eq!(phases.len(), 2);
        assert!(matches!(phases[0], SearchPhase::Initial { .. }));
        assert!(matches!(phases[1], SearchPhase::RefinementSkipped { 
            reason: SkipReason::UserCancelled 
        }));
    }

    // === Memory Tests ===

    #[test]
    fn test_memory_footprint_calculation() {
        let docs = 100_000;
        let fast_dims = 256;
        let quality_dims = 384;

        let fast_bytes = docs * fast_dims * 2;  // f16
        let quality_bytes = docs * quality_dims * 2;

        assert_eq!(fast_bytes, 51_200_000);     // ~51 MB
        assert_eq!(quality_bytes, 76_800_000);  // ~77 MB
    }

    // === Animation Tests ===

    #[test]
    fn test_should_animate_threshold() {
        let changes = RankChanges {
            promoted: vec![(1, 5, 1)],
            demoted: vec![(2, 1, 5)],
            stable: 8,
            correlation: 0.8,
        };

        // 2 changes out of 10 = 20%
        assert!(TwoTierRenderer::should_animate(&changes, 0.1));
        assert!(!TwoTierRenderer::should_animate(&changes, 0.3));
    }
}
