        // Search
        let client = DaemonClient::with_socket_path(socket);
        let searcher = TwoTierSearcher::new(create_fast_embedder(), client, Arc::new(index), config);

        let phases: Vec<_> = searcher.search("test query", 10).collect().await;

        assert!(phases.len() >= 2);
        assert!(matches!(phases[0], SearchPhase::Initial { .. }));

        daemon.shutdown().await;
    }

    #[tokio::test]
    async fn test_background_quality_indexing() {
        let tmp = TempDir::new().unwrap();
        let docs = load_test_docs(1000);
        let mut config = TwoTierConfig::default();
        config.quality_background = true;

        let index = build_two_tier_index(&docs, &config, &Output::null()).await.unwrap();

        // Should return FastOnly immediately
        assert!(matches!(index.metadata.status, IndexStatus::FastOnly));

        // Wait for background job
        tokio::time::sleep(Duration::from_secs(5)).await;

        // Reload and check
        let index = TwoTierIndex::load(&tmp.path().join("index")).unwrap();
        assert!(matches!(index.metadata.status, 
            IndexStatus::QualityPartial { .. } | IndexStatus::Complete { .. }
        ));
    }

    #[tokio::test]
    async fn test_daemon_fallback() {
        // No daemon running
        let config = TwoTierConfig {
            fallback_on_daemon_error: true,
            ..Default::default()
        };

        let index = create_test_index_fast_only();
        let client = DaemonClient::with_config(ClientConfig {
            socket_path: PathBuf::from("/nonexistent.sock"),
            auto_spawn: false,
            ..Default::default()
        });

        let searcher = TwoTierSearcher::new(create_fast_embedder(), client, index, config);
        let phases: Vec<_> = searcher.search("test", 10).collect().await;

        // Should get initial results, then fallback
        assert!(matches!(phases.last(), Some(SearchPhase::RefinementSkipped { 
            reason: SkipReason::DaemonUnavailable 
        }) | Some(SearchPhase::RefinementFailed { .. })));
    }

    #[tokio::test]
    async fn test_score_normalization_integration() {
        let daemon = spawn_test_daemon(&temp_socket()).await;
        let index = create_test_index_complete();
        let searcher = create_two_tier_searcher(index, daemon.socket_path());

        let phases: Vec<_> = searcher.search("machine learning", 10).collect().await;

        if let Some(SearchPhase::Refined { results, .. }) = phases.get(1) {
            // All blended scores should be in [0, 1]
            for result in results {
                assert!(result.score >= 0.0 && result.score <= 1.0,
                    "Blended score {} out of range", result.score);
            }
        }

