## 9. E2E Test Script

```bash
#!/bin/bash
# tests/e2e/two_tier_search.sh
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
XF_BIN="${PROJECT_ROOT}/target/release/xf"
TEST_DATA="${PROJECT_ROOT}/tests/fixtures/sample_archive.zip"
LOG_DIR="${SCRIPT_DIR}/logs"
TIMESTAMP=$(date +%Y%m%d_%H%M%S)
LOG_FILE="${LOG_DIR}/two_tier_e2e_${TIMESTAMP}.log"

RED="\033[0;31m"; GREEN="\033[0;32m"; YELLOW="\033[1;33m"; NC="\033[0m"

mkdir -p "$LOG_DIR"

log() { local ts=$(date +"%Y-%m-%d %H:%M:%S.%3N"); echo "[$ts] [$1] $2" | tee -a "$LOG_FILE"; }
log_info() { log "INFO" "$*"; }
log_error() { log "ERROR" "$*"; echo -e "${RED}✗ $*${NC}"; }
log_success() { log "SUCCESS" "$*"; echo -e "${GREEN}✓ $*${NC}"; }

assert_lt() { (( $(echo "$1 < $2" | bc -l) )) && log_success "$3" || { log_error "$3: $1 >= $2"; return 1; }; }
assert_contains() { [[ "$1" == *"$2"* ]] && log_success "$3" || { log_error "$3: missing \"$2\""; return 1; }; }

# === Environment Logging ===
log_env() {
    log_info "=== Environment ==="
    log_info "OS: $(uname -a)"
    log_info "CPU: $(nproc) cores"
    log_info "Memory: $(free -h | grep Mem | awk "{print \$2}")"
    log_info "xf version: $("$XF_BIN" --version 2>&1 || echo "unknown")"
    log_info "Working dir: $PROJECT_ROOT"
}

# === Setup ===
setup() {
    log_info "=== Setup ==="
    export TEST_WORKSPACE=$(mktemp -d)
    log_info "Workspace: $TEST_WORKSPACE"

    cargo build --release 2>&1 | tail -5 | tee -a "$LOG_FILE"
    "$XF_BIN" import "$TEST_DATA" --data-dir "$TEST_WORKSPACE" 2>&1 | tee -a "$LOG_FILE"

    log_info "Building two-tier index..."
    local start=$(date +%s.%N)
    "$XF_BIN" index --data-dir "$TEST_WORKSPACE" --two-tier 2>&1 | tee -a "$LOG_FILE"
    local elapsed=$(echo "$(date +%s.%N) - $start" | bc)
    log_info "Index build time: ${elapsed}s"

    log_success "Setup complete"
}

cleanup() {
    log_info "=== Cleanup ==="
    "$XF_BIN" daemon stop --data-dir "$TEST_WORKSPACE" 2>&1 || true
    [[ -n "${TEST_WORKSPACE:-}" && -d "$TEST_WORKSPACE" ]] && rm -rf "$TEST_WORKSPACE"
}
trap cleanup EXIT

# === Tests ===
test_daemon_startup() {
    log_info "=== Test: Daemon Startup ==="
    local start=$(date +%s.%N)
    "$XF_BIN" daemon start --data-dir "$TEST_WORKSPACE" 2>&1 | tee -a "$LOG_FILE"
    local startup_time=$(echo "$(date +%s.%N) - $start" | bc)
    log_info "Daemon startup: ${startup_time}s"

    sleep 1
    local status=$("$XF_BIN" daemon status --data-dir "$TEST_WORKSPACE" --json 2>&1)
    assert_contains "$status" "\"running\":true" "Daemon running"
    assert_lt "$startup_time" "5.0" "Startup < 5s"
}

test_fast_only_search() {
    log_info "=== Test: Fast-Only Search ==="
    local start=$(date +%s.%N)
    local result=$("$XF_BIN" search "machine learning" --fast-only --data-dir "$TEST_WORKSPACE" --json 2>&1)
    local elapsed_ms=$(echo "($(date +%s.%N) - $start) * 1000" | bc)

    log_info "Fast search: ${elapsed_ms}ms"
    assert_lt "$elapsed_ms" "10.0" "Fast search < 10ms"
    assert_contains "$result" "\"results\":" "Has results"
}

test_two_tier_progressive() {
    log_info "=== Test: Two-Tier Progressive ==="
    local result=$("$XF_BIN" search "neural network" --two-tier --data-dir "$TEST_WORKSPACE" --json --verbose 2>&1)

    local fast_ms=$(echo "$result" | jq -r ".phases[0].latency_ms // 0")
    local refine_ms=$(echo "$result" | jq -r ".phases[1].latency_ms // 0")
    local correlation=$(echo "$result" | jq -r ".phases[1].changes.correlation // 0")

    log_info "Fast: ${fast_ms}ms, Refine: ${refine_ms}ms, Correlation: $correlation"

    assert_lt "$fast_ms" "5.0" "Fast phase < 5ms"
    assert_lt "$refine_ms" "200.0" "Refine < 200ms"
}

test_background_quality_indexing() {
    log_info "=== Test: Background Quality Indexing ==="
    local bg_workspace=$(mktemp -d)

    # Index with background quality
    "$XF_BIN" import "$TEST_DATA" --data-dir "$bg_workspace" 2>&1 | tee -a "$LOG_FILE"
    "$XF_BIN" index --data-dir "$bg_workspace" --two-tier --quality-background 2>&1 | tee -a "$LOG_FILE"

    # Check status
    local status=$("$XF_BIN" index --quality-status --data-dir "$bg_workspace" --json 2>&1)
    log_info "Quality status: $status"

    assert_contains "$status" "status" "Has status field"

    rm -rf "$bg_workspace"
    log_success "Background indexing test passed"
}

test_metrics_logging() {
    log_info "=== Test: Metrics Logging ==="
    local result=$("$XF_BIN" search "test" --two-tier --data-dir "$TEST_WORKSPACE" --json --metrics 2>&1)

    assert_contains "$result" "\"metrics\":" "Has metrics"
    assert_contains "$result" "\"fast_latency_ms\":" "Has fast latency"
    assert_contains "$result" "\"daemon_used\":" "Has daemon flag"

    log_success "Metrics logging test passed"
}

# === Main ===
main() {
    log_info "========================================="
    log_info "Two-Tier Progressive Search E2E Tests"
    log_info "Started: $(date)"
    log_info "========================================="

    log_env
    setup

    local failed=0 passed=0

    for test_fn in test_daemon_startup test_fast_only_search test_two_tier_progressive test_background_quality_indexing test_metrics_logging; do
        if $test_fn; then ((passed++)); else ((failed++)); log_error "FAILED: $test_fn"; fi
        echo ""
    done

    log_info "========================================="
    log_info "Results: $passed passed, $failed failed"
    log_info "Log: $LOG_FILE"
    log_info "========================================="

    [[ $failed -gt 0 ]] && exit 1
    log_success "All tests passed!"
}

main "$@"
